def {{nama_fungsi}}(path='.env', set_environ=True):
    """Parse .env sederhana."""
    import os
    env = {}
    try:
        with open(path) as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith('#'):
                    continue
                if '=' not in line:
                    continue
                k, v = line.split('=', 1)
                k = k.strip()
                v = v.strip().strip('"').strip("'")
                env[k] = v
                if set_environ:
                    os.environ.setdefault(k, v)
    except FileNotFoundError:
        pass
    return env

def {{nama_fungsi}}(path):
    """Return dict section -> dict."""
    import configparser
    cp = configparser.ConfigParser()
    cp.read(path, encoding='utf-8')
    return {s: dict(cp[s]) for s in cp.sections()}

