def {{nama_fungsi}}(path):
    """YAML-lite: hanya key: value flat / list sederhana."""
    import ast
    data = {}
    current_key = None
    with open(path, encoding='utf-8') as f:
        for raw in f:
            line = raw.strip()
            if not line or line.startswith('#'):
                continue
            if line.startswith('- '):
                if current_key:
                    data.setdefault(current_key, []).append(line[2:].strip())
                continue
            if ':' in line:
                k, v = line.split(':', 1)
                k = k.strip()
                v = v.strip()
                current_key = k
                if v == '':
                    data[k] = []
                else:
                    try:
                        data[k] = ast.literal_eval(v)
                    except Exception:
                        data[k] = v
    return data

def {{nama_fungsi}}(default, file_cfg=None, env_prefix='', cli_args=None):
    """Merge config layers. env_prefix misal 'APP_'."""
    import os
    result = {}
    result.update(default or {})
    if file_cfg:
        result.update(file_cfg)
    if env_prefix:
        plen = len(env_prefix)
        for k, v in os.environ.items():
            if k.startswith(env_prefix):
                result[k[plen:].lower()] = v
    if cli_args:
        result.update({k: v for k, v in cli_args.items() if v is not None})
    return result

def {{nama_fungsi}}(config, schema):
    """schema: dict key -> type atau tuple types. Return list errors."""
    errors = []
    for key, expected in schema.items():
        if key not in config:
            errors.append(f"Missing key: {key}")
            continue
        val = config[key]
        if not isinstance(val, expected):
            errors.append(f"{key}: expected {expected}, got {type(val).__name__}")
    return errors

